class Solution {
    public List<List<Integer>> largeGroupPositions(String s) {
        List<List<Integer>> result = new ArrayList<>();
        int start = 0;
        int end = 0;
        StringBuilder sb = new StringBuilder(s);
        while (end < s.length()) {
            int count = 1;
            while (sb.charAt(end) == sb.charAt(start)) {
                start++;
                count++;
            }
            end++;
            result.add(Arrays.asList(new int[]{start, end - count + 1}));
        }
        return result;
    }
}
```

